class ConsensusStateMachine {
    constructor() {
        this.state = 'IDLE';
        this.proposedBlock = null;
        this.votes = new Map();
        this.threshold = 0;
    }

    setThreshold(totalNodes) {
        // Need 2/3 + 1 for BFT
        this.threshold = Math.floor((2 * totalNodes) / 3) + 1;
    }

    propose(block) {
        if (this.state !== 'IDLE') {
            throw new Error('Cannot propose: not in IDLE state');
        }
        this.proposedBlock = block;
        this.state = 'PROPOSED';
        console.log(`Block proposed: ${block.hash}`);
        return this.state;
    }

    vote(nodeId, approve) {
        if (this.state !== 'PROPOSED') {
            throw new Error('Cannot vote: no active proposal');
        }
        this.votes.set(nodeId, approve);

        const approvals = [...this.votes.values()].filter(v => v).length;
        console.log(`Vote from ${nodeId}: ${approve} (${approvals}/${this.threshold})`);

        if (approvals >= this.threshold) {
            this.state = 'COMMITTED';
            console.log('Consensus REACHED! Block committed.');
        }
        return this.state;
    }

    reset() {
        this.state = 'IDLE';
        this.proposedBlock = null;
        this.votes.clear();
    }
}

// Usage
const consensus = new ConsensusStateMachine();
consensus.setThreshold(4);
consensus.propose({ hash: '0xabc123' });
consensus.vote('node1', true);
consensus.vote('node2', true);
consensus.vote('node3', true);

package consensus

import "time"

// Block represents a block to be added to the chain
type Block struct {
    Index        uint64
    Timestamp    time.Time
    Data         []byte
    PreviousHash string
    Hash         string
    Proposer     string
}

// ConsensusEngine defines the interface for consensus mechanisms
type ConsensusEngine interface {
    // Propose a new block to the network
    Propose(block *Block) error

    // Verify if a block is valid according to consensus rules
    Verify(block *Block) bool

    // Finalize commits a block after consensus is reached
    Finalize(block *Block) error

    // IsFinalized checks if a block has achieved finality
    IsFinalized(blockHash string) bool
}

// ConsensusConfig holds configuration for consensus
type ConsensusConfig struct {
    BlockTime       time.Duration
    RequiredVotes   int
    TotalValidators int
}

// BaseConsensus provides common functionality
type BaseConsensus struct {
    config    ConsensusConfig
    finalized map[string]bool
}

func (bc *BaseConsensus) IsFinalized(blockHash string) bool {
    return bc.finalized[blockHash]
}

// Example: Check if we have enough votes for BFT
func (bc *BaseConsensus) HasQuorum(votes int) bool {
    // BFT requires 2f+1 votes where n = 3f+1
    f := (bc.config.TotalValidators - 1) / 3
    required := 2*f + 1
    return votes >= required
}
